B.aAy=new A.fE("1. \u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 Nuva","Nuva \u2014 \u043c\u043e\u0431\u0438\u043b\u044c\u043d\u043e\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0441\u043e\u0435\u0434\u0438\u043d\u044f\u0435\u0442 \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u0435\u0439 \u0441 \u043b\u0438\u0446\u0435\u043d\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u043c\u0438 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0430\u043c\u0438 \u0432 \u0420\u0435\u0441\u043f\u0443\u0431\u043b\u0438\u043a\u0435 \u041a\u0430\u0437\u0430\u0445\u0441\u0442\u0430\u043d. \u041c\u044b \u0432\u044b\u0441\u0442\u0443\u043f\u0430\u0435\u043c \u0430\u0433\u0440\u0435\u0433\u0430\u0442\u043e\u0440\u043e\u043c: \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u043c \u043d\u0430\u0439\u0442\u0438 \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u0430, \u043f\u0440\u043e\u0432\u0435\u0441\u0442\u0438 \u0441\u0435\u0441\u0441\u0438\u044e \u0438 \u043e\u043f\u043b\u0430\u0442\u0438\u0442\u044c \u0443\u0441\u043b\u0443\u0433\u0443 \u0447\u0435\u0440\u0435\u0437 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0435.")
B.aAL=new A.fE("2. \u041a\u0442\u043e \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0443\u0441\u043b\u0443\u0433\u0443","\u041f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u0443\u0441\u043b\u0443\u0433\u0443 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442 \u2014 \u043d\u0435 Nuva. Nuva \u043e\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0440\u0430\u0431\u043e\u0442\u0443 \u043f\u043b\u0430\u0442\u0444\u043e\u0440\u043c\u044b, \u0432\u0435\u0440\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044e \u0434\u0438\u043f\u043b\u043e\u043c\u043e\u0432 \u0438 \u0443\u0434\u043e\u0431\u0441\u0442\u0432\u043e \u0440\u0430\u0441\u0447\u0451\u0442\u043e\u0432.")
B.aAI=new A.fE("3. \u041a\u0430\u043a \u043c\u044b \u0437\u0430\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u043c","\u041c\u044b \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u043c \u0441\u0435\u0440\u0432\u0438\u0441\u043d\u044b\u0439 \u0441\u0431\u043e\u0440 \u0441 \u043a\u0430\u0436\u0434\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 (\u043a\u043e\u043c\u0438\u0441\u0441\u0438\u044f \u0443\u043a\u0430\u0437\u0430\u043d\u0430 \u043f\u0440\u0438 \u043e\u043f\u043b\u0430\u0442\u0435). \u041f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0443 \u0432\u044b\u043f\u043b\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u043e\u0441\u0442\u0430\u0432\u0448\u0430\u044f\u0441\u044f \u0441\u0443\u043c\u043c\u0430 \u043f\u043e\u0441\u043b\u0435 \u0443\u0441\u043f\u0435\u0448\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u044f \u0441\u0435\u0441\u0441\u0438\u0438.")
B.aAC=new A.fE("4. \u041e\u0442\u043c\u0435\u043d\u0430 \u0438 \u0432\u043e\u0437\u0432\u0440\u0430\u0442","\u041e\u0442\u043c\u0435\u043d\u0430 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e \u0437\u0430 12 \u0447\u0430\u0441\u043e\u0432 \u0434\u043e \u0441\u0435\u0441\u0441\u0438\u0438. \u0415\u0441\u043b\u0438 \u0441\u0435\u0441\u0441\u0438\u044f \u043d\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043b\u0430\u0441\u044c \u043f\u043e \u0432\u0438\u043d\u0435 \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u0430 \u2014 \u0432\u043e\u0437\u0432\u0440\u0430\u0442 100%. \u0415\u0441\u043b\u0438 \u043f\u043e \u0432\u0430\u0448\u0435\u0439 \u0432\u0438\u043d\u0435 \u0431\u0435\u0437 \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u044f \u2014 \u0441\u0431\u043e\u0440 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f.")
B.aAA=new A.fE("5. \u0413\u0430\u0440\u0430\u043d\u0442\u0438\u044f Nuva","\u0415\u0441\u043b\u0438 \u043f\u0435\u0440\u0432\u0430\u044f \u0441\u0435\u0441\u0441\u0438\u044f \u0441 \u043f\u043e\u0434\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u043c \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u043e\u043c \u043d\u0435 \u043f\u043e\u0434\u043e\u0448\u043b\u0430 \u2014 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e \u043f\u043e\u0434\u0431\u0435\u0440\u0451\u043c \u0434\u0440\u0443\u0433\u043e\u0433\u043e.")
B.aAD=new A.fE("6. \u0417\u0430\u043f\u0440\u0435\u0442\u044b","\u0412 \u0447\u0430\u0442\u0435 \u0437\u0430\u043f\u0440\u0435\u0449\u0435\u043d\u043e: \u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u043a\u043e\u043d\u0442\u0430\u043a\u0442\u0430\u043c\u0438 \u0432\u043d\u0435 Nuva (\u0442\u0435\u043b\u0435\u0444\u043e\u043d\u044b, \u043c\u0435\u0441\u0441\u0435\u043d\u0434\u0436\u0435\u0440\u044b), \u043f\u0435\u0440\u0435\u0434\u0430\u0432\u0430\u0442\u044c \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044b \u044d\u043a\u0441\u0442\u0440\u0435\u043c\u0438\u0441\u0442\u0441\u043a\u043e\u0433\u043e \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u0430, \u043d\u0430\u0440\u0443\u0448\u0430\u0442\u044c \u0437\u0430\u043a\u043e\u043d\u043e\u0434\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e \u0420\u041a. \u041d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u0435 \u2192 \u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u043a\u0430 \u0430\u043a\u043a\u0430\u0443\u043d\u0442\u0430 \u0431\u0435\u0437 \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430 \u0441\u0440\u0435\u0434\u0441\u0442\u0432.")
B.aAO=new A.fE("7. \u041e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u0438\u0435 \u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0441\u0442\u0438","Nuva \u043d\u0435 \u0437\u0430\u043c\u0435\u043d\u044f\u0435\u0442 \u044d\u043a\u0441\u0442\u0440\u0435\u043d\u043d\u0443\u044e \u043c\u0435\u0434\u0438\u0446\u0438\u043d\u0441\u043a\u0443\u044e \u043f\u043e\u043c\u043e\u0449\u044c. \u0412 \u043a\u0440\u0438\u0437\u0438\u0441\u043d\u043e\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u0437\u0432\u043e\u043d\u0438\u0442\u0435 150 / 112.")
